import{_ as e,c as a,o as t,a as r}from"./app.8a0f1aa2.js";const g='{"title":"What is NTAK.REST?","description":"","frontmatter":{},"headers":[{"level":2,"title":"Motivation","slug":"motivation"},{"level":2,"title":"Technologies","slug":"technologies"},{"level":3,"title":"Framework","slug":"framework"},{"level":3,"title":"Hosting","slug":"hosting"}],"relativePath":"en/guide/what-is-ntak.rest.md","lastUpdated":1654874118000}',o={name:"en/guide/what-is-ntak.rest.md"},n=r('<h1 id="what-is-ntak-rest" tabindex="-1">What is NTAK.REST? <a class="header-anchor" href="#what-is-ntak-rest" aria-hidden="true">#</a></h1><p>NTAK.TEST is wrapper for <a href="https://info.ntak.hu/" target="_blank" rel="noopener noreferrer">NTAK</a> to provide a much simpler interface.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-hidden="true">#</a></h2><p>When we created our own application to report to NTAK, it took a developer for months. <br> It has a huge, complicated and still not complete documentation.</p><p>So we decided to create a service for other PMSes, because we know every popular programming language can make an HTTP <br> request, but not every application are prepared for queued jobs and/or scheduled tasks.</p><p>With NTAK.REST you can report the following events without making the user and/or guest to wait for us:</p><ul><li>Reservation creation</li><li>Reservation update</li><li>Room change</li><li>Checkin</li><li>Checkout</li></ul><p>Also, we are handling the scheduler for the Daily Closing report.</p><h2 id="technologies" tabindex="-1">Technologies <a class="header-anchor" href="#technologies" aria-hidden="true">#</a></h2><p>There is no reason to hide it. Or we just like to flex.</p><h3 id="framework" tabindex="-1">Framework <a class="header-anchor" href="#framework" aria-hidden="true">#</a></h3><p>We are using <a href="https://laravel.com" target="_blank" rel="noopener noreferrer">Laravel</a> 9 LTS to enjoy the development of clean code.</p><h3 id="hosting" tabindex="-1">Hosting <a class="header-anchor" href="#hosting" aria-hidden="true">#</a></h3><p>Laravel has a first-party hosting called <a href="http://vapor.laravel.com" target="_blank" rel="noopener noreferrer">Laravel Vapor</a>. We use it, we love. <br> Easy to learn and it&#39;s blazing fast. It&#39;s managing tons of services out of the box for us.</p><p>On top of that we are also using <a href="https://laravel.com/docs/9.x/octane" target="_blank" rel="noopener noreferrer">Laravel Octane</a>.</p><p>With these two wonderful tools, we are able to provide an extremely fast API for you. Average response time is ~25 ms.</p>',16),i=[n];function s(l,h,d,p,c,u){return t(),a("div",null,i)}var m=e(o,[["render",s]]);export{g as __pageData,m as default};
